// src/pages/dashboard/ContentDashboard.js
import React from "react";
import Layout from "../../components/layout/Layout";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

function ContentDashboard() {
  const chartData = {
    labels: ["Week 1", "Week 2", "Week 3", "Week 4"],
    datasets: [
      {
        label: "New Content Uploaded",
        data: [5, 8, 3, 6],
        backgroundColor: "#059669",
        borderRadius: 6,
      },
      {
        label: "Content Updates",
        data: [2, 4, 3, 5],
        backgroundColor: "#10b981",
        borderRadius: 6,
      },
    ],
  };

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: { position: "top" },
      title: { display: false },
    },
  };

  return (
    <Layout pageTitle="Content Creator Dashboard">

      {/* Header Section */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 style={{ fontWeight: "700" }}>
          Content Creator Overview
        </h2>
        <button className="btn btn-success fw-semibold">
          + Add New Content
        </button>
      </div>

      {/* STAT CARDS */}
      <div className="row g-4 mb-4">
        <div className="col-md-4">
          <div className="card shadow-sm p-4" style={{ borderRadius: "12px" }}>
            <h6 className="text-muted">Total Content</h6>
            <h2 className="fw-bold">24</h2>
            <span className="text-success">+3 this week</span>
          </div>
        </div>

        <div className="col-md-4">
          <div className="card shadow-sm p-4" style={{ borderRadius: "12px" }}>
            <h6 className="text-muted">Drafts</h6>
            <h2 className="fw-bold">5</h2>
            <span className="text-warning">Pending review</span>
          </div>
        </div>

        <div className="col-md-4">
          <div className="card shadow-sm p-4" style={{ borderRadius: "12px" }}>
            <h6 className="text-muted">Published</h6>
            <h2 className="fw-bold">19</h2>
            <span className="text-success">+2 this week</span>
          </div>
        </div>
      </div>

      {/* CHART */}
      <div className="card shadow-sm p-4 mb-4" style={{ borderRadius: "12px" }}>
        <h5 className="mb-4 fw-semibold">Content Activity Overview</h5>
        <Bar data={chartData} options={chartOptions} />
      </div>

      {/* ACTION PANEL */}
      <div
        className="card shadow-sm p-4"
        style={{
          borderRadius: "12px",
          background: "#f0fdf4",
        }}
      >
        <h5 className="mb-3 fw-semibold">Manage Content</h5>
        <p style={{ lineHeight: "1.6" }}>
          Upload new course materials, update existing content, and
          track performance to keep learners engaged.
        </p>
        <button className="btn btn-success fw-semibold">
          Create New Content
        </button>
      </div>

    </Layout>
  );
}

export default ContentDashboard;
